}





bool isConvex(vector<Point> p)

{

  int sz = (int)p.size();



  if(sz < 3)return false;//boundary case, we treat a point or a line as not convex



  bool isLeft = ccwtest(p[0],p[1],p[2]);



  for(int i=1; i<(int)p.size();i++)

    if(ccwtest(p[i],p[(i+1)%sz],p[(i+2)%sz]) != isLeft)

      return false;



  return true;

}





