{

  double ux = b.x - a.x, uy = b.y - a.y;

  double vx = c.x - a.x, vy = c.y - a.y;

  return acos((ux*vx + uy*vy)/sqrt((ux*ux + uy*uy) * (vx*vx + vy*vy)));

