int bin_search_line(double x, double y) {

	int l = 0, r = m, line = 0;

	while (l <= r) {

		int mid = (l + r) >> 1;

		if ((y - L[mid]) * w > x * (R[mid] - L[mid])) {

			l = mid + 1;

		} else r = mid - 1, line = mid;

    }

    return line;

}



int bin_search_level(int end) {

	int l = 0, r = end, level = -1;

	while (l <= r) {

		int mid = (l + r) >> 1;

		if ((L[end] - L[mid] + R[end] - R[mid]) * w > 2 * (w * h - s)) {

			l = mid + 1;

		} else r = mid - 1, level = mid;

	}

	return level;

